select 
from model_call_log


        and (call_id like #{keywordLike}
        or trace_id like #{keywordLike}
        or task_id like #{keywordLike}
        or config_id like #{keywordLike}
        or model_code like #{keywordLike}
        or model_name like #{keywordLike}
        or provider like #{keywordLike})


        and call_type = #{query.callType}


        and status = #{query.status}


        and stage_code = #{query.stageCode}


        and model_code = #{query.modelCode}


order by created_at desc

